read_group(Bin, FieldNum) ->
    {NumBytes, EndTagLen} = read_gr_b(Bin, 0, 0, 0, 0, FieldNum),
    <<Group:NumBytes/binary, _:EndTagLen/binary, Rest/binary>> = Bin,
    {Group, Rest}.

%% Like skipping over fields, but record the total length,
%% Each field is <(FieldNum bsl 3) bor FieldType> ++ <FieldValue>
%% Record the length because varints may be non-optimally encoded.
%%
%% Groups can be nested, but assume the same FieldNum cannot be nested
%% because group field numbers are shared with the rest of the fields
%% numbers. Thus we can search just for an group-end with the same
%% field number.
%%
%% (The only time the same group field number could occur would
%% be in a nested sub message, but then it would be inside a
%% length-delimited entry, which we skip-read by length.)
read_gr_b(<<1:1, X:7, Tl/binary>>, N, Acc, NumBytes, TagLen, FieldNum)
  when N < (32-7) ->
    read_gr_b(Tl, N+7, X bsl N + Acc, NumBytes, TagLen+1, FieldNum);
read_gr_b(<<0:1, X:7, Tl/binary>>, N, Acc, NumBytes, TagLen,
          FieldNum) ->
    Key = X bsl N + Acc,
    TagLen1 = TagLen + 1,
    case {Key bsr 3, Key band 7} of
        {FieldNum, 4} -> % 4 = group_end
            {NumBytes, TagLen1};
        {_, 0} -> % 0 = varint
            read_gr_vi(Tl, 0, NumBytes + TagLen1, FieldNum);
        {_, 1} -> % 1 = bits64
            <<_:64, Tl2/binary>> = Tl,
            read_gr_b(Tl2, 0, 0, NumBytes + TagLen1 + 8, 0, FieldNum);
        {_, 2} -> % 2 = length_delimited
            read_gr_ld(Tl, 0, 0, NumBytes + TagLen1, FieldNum);
        {_, 3} -> % 3 = group_start
            read_gr_b(Tl, 0, 0, NumBytes + TagLen1, 0, FieldNum);
        {_, 4} -> % 4 = group_end
            read_gr_b(Tl, 0, 0, NumBytes + TagLen1, 0, FieldNum);
        {_, 5} -> % 5 = bits32
            <<_:32, Tl2/binary>> = Tl,
            read_gr_b(Tl2, 0, 0, NumBytes + TagLen1 + 4, 0, FieldNum)
    end.

read_gr_vi(<<1:1, _:7, Tl/binary>>, N, NumBytes, FieldNum)
  when N < (64-7) ->
    read_gr_vi(Tl, N+7, NumBytes+1, FieldNum);
read_gr_vi(<<0:1, _:7, Tl/binary>>, _, NumBytes, FieldNum) ->
    read_gr_b(Tl, 0, 0, NumBytes+1, 0, FieldNum).

read_gr_ld(<<1:1, X:7, Tl/binary>>, N, Acc, NumBytes, FieldNum)
  when N < (64-7) ->
    read_gr_ld(Tl, N+7, X bsl N + Acc, NumBytes+1, FieldNum);
read_gr_ld(<<0:1, X:7, Tl/binary>>, N, Acc, NumBytes, FieldNum) ->
    Len = X bsl N + Acc,
    NumBytes1 = NumBytes + 1,
    <<_:Len/binary, Tl2/binary>> = Tl,
    read_gr_b(Tl2, 0, 0, NumBytes1 + Len, 0, FieldNum).

merge_msgs(Prev, New, MsgName) when is_atom(MsgName) -> merge_msgs(Prev, New, MsgName, []).

merge_msgs(Prev, New, MsgName, Opts) ->
    TrUserData = proplists:get_value(user_data, Opts),
    case MsgName of
        'yuzu.agent.v1.AgentInfo' -> 'merge_msg_yuzu.agent.v1.AgentInfo'(Prev, New, TrUserData);
        'yuzu.agent.v1.RegisterRequest' -> 'merge_msg_yuzu.agent.v1.RegisterRequest'(Prev, New, TrUserData);
        'yuzu.agent.v1.RegisterResponse' -> 'merge_msg_yuzu.agent.v1.RegisterResponse'(Prev, New, TrUserData);
        'yuzu.agent.v1.HeartbeatRequest' -> 'merge_msg_yuzu.agent.v1.HeartbeatRequest'(Prev, New, TrUserData);
        'yuzu.agent.v1.HeartbeatResponse' -> 'merge_msg_yuzu.agent.v1.HeartbeatResponse'(Prev, New, TrUserData);
        'yuzu.agent.v1.CommandRequest' -> 'merge_msg_yuzu.agent.v1.CommandRequest'(Prev, New, TrUserData);
        'yuzu.agent.v1.CommandResponse' -> 'merge_msg_yuzu.agent.v1.CommandResponse'(Prev, New, TrUserData);
        'yuzu.agent.v1.InventoryReport' -> 'merge_msg_yuzu.agent.v1.InventoryReport'(Prev, New, TrUserData);
        'yuzu.agent.v1.InventoryAck' -> 'merge_msg_yuzu.agent.v1.InventoryAck'(Prev, New, TrUserData);
        'yuzu.agent.v1.CheckForUpdateRequest' -> 'merge_msg_yuzu.agent.v1.CheckForUpdateRequest'(Prev, New, TrUserData);
        'yuzu.agent.v1.CheckForUpdateResponse' -> 'merge_msg_yuzu.agent.v1.CheckForUpdateResponse'(Prev, New, TrUserData);
        'yuzu.agent.v1.DownloadUpdateRequest' -> 'merge_msg_yuzu.agent.v1.DownloadUpdateRequest'(Prev, New, TrUserData);
        'yuzu.agent.v1.DownloadUpdateChunk' -> 'merge_msg_yuzu.agent.v1.DownloadUpdateChunk'(Prev, New, TrUserData);
        'yuzu.common.v1.Platform' -> 'merge_msg_yuzu.common.v1.Platform'(Prev, New, TrUserData);
        'yuzu.common.v1.PluginInfo' -> 'merge_msg_yuzu.common.v1.PluginInfo'(Prev, New, TrUserData);
        'yuzu.common.v1.ErrorDetail' -> 'merge_msg_yuzu.common.v1.ErrorDetail'(Prev, New, TrUserData);
        'yuzu.common.v1.Timestamp' -> 'merge_msg_yuzu.common.v1.Timestamp'(Prev, New, TrUserData);
        'yuzu.common.v1.ScopeExpression' -> 'merge_msg_yuzu.common.v1.ScopeExpression'(Prev, New, TrUserData);
        'yuzu.common.v1.ScopeCondition' -> 'merge_msg_yuzu.common.v1.ScopeCondition'(Prev, New, TrUserData);
        'yuzu.common.v1.ScopeCombinator' -> 'merge_msg_yuzu.common.v1.ScopeCombinator'(Prev, New, TrUserData)
    end.

-compile({nowarn_unused_function,'merge_msg_yuzu.agent.v1.AgentInfo'/3}).
'merge_msg_yuzu.agent.v1.AgentInfo'(PMsg, NMsg, TrUserData) ->
    S1 = #{},
    S2 = case {PMsg, NMsg} of
             {_, #{agent_id := NFagent_id}} -> S1#{agent_id => NFagent_id};
             {#{agent_id := PFagent_id}, _} -> S1#{agent_id => PFagent_id};
             _ -> S1
         end,
    S3 = case {PMsg, NMsg} of
             {_, #{hostname := NFhostname}} -> S2#{hostname => NFhostname};
             {#{hostname := PFhostname}, _} -> S2#{hostname => PFhostname};
             _ -> S2
         end,
    S4 = case {PMsg, NMsg} of
             {#{platform := PFplatform}, #{platform := NFplatform}} -> S3#{platform => 'merge_msg_yuzu.common.v1.Platform'(PFplatform, NFplatform, TrUserData)};
             {_, #{platform := NFplatform}} -> S3#{platform => NFplatform};
             {#{platform := PFplatform}, _} -> S3#{platform => PFplatform};
             {_, _} -> S3
         end,
    S5 = case {PMsg, NMsg} of
             {_, #{agent_version := NFagent_version}} -> S4#{agent_version => NFagent_version};
             {#{agent_version := PFagent_version}, _} -> S4#{agent_version => PFagent_version};
             _ -> S4
         end,
    S6 = case {PMsg, NMsg} of
             {#{plugins := PFplugins}, #{plugins := NFplugins}} -> S5#{plugins => 'erlang_++'(PFplugins, NFplugins, TrUserData)};
             {_, #{plugins := NFplugins}} -> S5#{plugins => NFplugins};
             {#{plugins := PFplugins}, _} -> S5#{plugins => PFplugins};
             {_, _} -> S5
         end,
    case {PMsg, NMsg} of
        {#{scopable_tags := PFscopable_tags}, #{scopable_tags := NFscopable_tags}} -> S6#{scopable_tags => 'tr_merge_yuzu.agent.v1.AgentInfo.scopable_tags'(PFscopable_tags, NFscopable_tags, TrUserData)};
        {_, #{scopable_tags := NFscopable_tags}} -> S6#{scopable_tags => NFscopable_tags};
        {#{scopable_tags := PFscopable_tags}, _} -> S6#{scopable_tags => PFscopable_tags};
        {_, _} -> S6
    end.

