-compile({nowarn_unused_function,'merge_msg_yuzu.agent.v1.RegisterResponse'/3}).
'merge_msg_yuzu.agent.v1.RegisterResponse'(PMsg, NMsg, TrUserData) ->
    S1 = #{},
    S2 = case {PMsg, NMsg} of
             {_, #{session_id := NFsession_id}} -> S1#{session_id => NFsession_id};
             {#{session_id := PFsession_id}, _} -> S1#{session_id => PFsession_id};
             _ -> S1
         end,
    S3 = case {PMsg, NMsg} of
             {_, #{accepted := NFaccepted}} -> S2#{accepted => NFaccepted};
             {#{accepted := PFaccepted}, _} -> S2#{accepted => PFaccepted};
             _ -> S2
         end,
    S4 = case {PMsg, NMsg} of
             {_, #{reject_reason := NFreject_reason}} -> S3#{reject_reason => NFreject_reason};
             {#{reject_reason := PFreject_reason}, _} -> S3#{reject_reason => PFreject_reason};
             _ -> S3
         end,
    S5 = case {PMsg, NMsg} of
             {#{pending_commands := PFpending_commands}, #{pending_commands := NFpending_commands}} -> S4#{pending_commands => 'erlang_++'(PFpending_commands, NFpending_commands, TrUserData)};
             {_, #{pending_commands := NFpending_commands}} -> S4#{pending_commands => NFpending_commands};
             {#{pending_commands := PFpending_commands}, _} -> S4#{pending_commands => PFpending_commands};
             {_, _} -> S4
