verify_msg(Msg, MsgName) when is_atom(MsgName) -> verify_msg(Msg, MsgName, []).

verify_msg(Msg, MsgName, Opts) ->
    TrUserData = proplists:get_value(user_data, Opts),
    case MsgName of
        'yuzu.agent.v1.AgentInfo' -> 'v_msg_yuzu.agent.v1.AgentInfo'(Msg, [MsgName], TrUserData);
        'yuzu.agent.v1.RegisterRequest' -> 'v_msg_yuzu.agent.v1.RegisterRequest'(Msg, [MsgName], TrUserData);
        'yuzu.agent.v1.RegisterResponse' -> 'v_msg_yuzu.agent.v1.RegisterResponse'(Msg, [MsgName], TrUserData);
        'yuzu.agent.v1.HeartbeatRequest' -> 'v_msg_yuzu.agent.v1.HeartbeatRequest'(Msg, [MsgName], TrUserData);
        'yuzu.agent.v1.HeartbeatResponse' -> 'v_msg_yuzu.agent.v1.HeartbeatResponse'(Msg, [MsgName], TrUserData);
        'yuzu.agent.v1.CommandRequest' -> 'v_msg_yuzu.agent.v1.CommandRequest'(Msg, [MsgName], TrUserData);
        'yuzu.agent.v1.CommandResponse' -> 'v_msg_yuzu.agent.v1.CommandResponse'(Msg, [MsgName], TrUserData);
        'yuzu.agent.v1.InventoryReport' -> 'v_msg_yuzu.agent.v1.InventoryReport'(Msg, [MsgName], TrUserData);
        'yuzu.agent.v1.InventoryAck' -> 'v_msg_yuzu.agent.v1.InventoryAck'(Msg, [MsgName], TrUserData);
        'yuzu.agent.v1.CheckForUpdateRequest' -> 'v_msg_yuzu.agent.v1.CheckForUpdateRequest'(Msg, [MsgName], TrUserData);
        'yuzu.agent.v1.CheckForUpdateResponse' -> 'v_msg_yuzu.agent.v1.CheckForUpdateResponse'(Msg, [MsgName], TrUserData);
        'yuzu.agent.v1.DownloadUpdateRequest' -> 'v_msg_yuzu.agent.v1.DownloadUpdateRequest'(Msg, [MsgName], TrUserData);
        'yuzu.agent.v1.DownloadUpdateChunk' -> 'v_msg_yuzu.agent.v1.DownloadUpdateChunk'(Msg, [MsgName], TrUserData);
        'yuzu.common.v1.Platform' -> 'v_msg_yuzu.common.v1.Platform'(Msg, [MsgName], TrUserData);
        'yuzu.common.v1.PluginInfo' -> 'v_msg_yuzu.common.v1.PluginInfo'(Msg, [MsgName], TrUserData);
        'yuzu.common.v1.ErrorDetail' -> 'v_msg_yuzu.common.v1.ErrorDetail'(Msg, [MsgName], TrUserData);
        'yuzu.common.v1.Timestamp' -> 'v_msg_yuzu.common.v1.Timestamp'(Msg, [MsgName], TrUserData);
        'yuzu.common.v1.ScopeExpression' -> 'v_msg_yuzu.common.v1.ScopeExpression'(Msg, [MsgName], TrUserData);
        'yuzu.common.v1.ScopeCondition' -> 'v_msg_yuzu.common.v1.ScopeCondition'(Msg, [MsgName], TrUserData);
        'yuzu.common.v1.ScopeCombinator' -> 'v_msg_yuzu.common.v1.ScopeCombinator'(Msg, [MsgName], TrUserData);
        _ -> mk_type_error(not_a_known_message, Msg, [])
    end.


-compile({nowarn_unused_function,'v_submsg_yuzu.agent.v1.AgentInfo'/3}).
-dialyzer({nowarn_function,'v_submsg_yuzu.agent.v1.AgentInfo'/3}).
'v_submsg_yuzu.agent.v1.AgentInfo'(Msg, Path, TrUserData) -> 'v_msg_yuzu.agent.v1.AgentInfo'(Msg, Path, TrUserData).

-compile({nowarn_unused_function,'v_msg_yuzu.agent.v1.AgentInfo'/3}).
-dialyzer({nowarn_function,'v_msg_yuzu.agent.v1.AgentInfo'/3}).
'v_msg_yuzu.agent.v1.AgentInfo'(#{} = M, Path, TrUserData) ->
    case M of
        #{agent_id := F1} -> v_type_string(F1, [agent_id | Path], TrUserData);
        _ -> ok
    end,
    case M of
        #{hostname := F2} -> v_type_string(F2, [hostname | Path], TrUserData);
        _ -> ok
    end,
    case M of
        #{platform := F3} -> 'v_submsg_yuzu.common.v1.Platform'(F3, [platform | Path], TrUserData);
        _ -> ok
    end,
    case M of
        #{agent_version := F4} -> v_type_string(F4, [agent_version | Path], TrUserData);
        _ -> ok
    end,
    case M of
